309	/// Remove kit assets from target repo.
310	///
311	/// # Arguments
312	/// * `args` - Vacate arguments (burc.env path)
313	///
314	/// # Returns
315	/// VacateResult with removal summary, or error message
316	pub fn vofe_vacate(args: &vofe_VacateArgs) -> Result<vofe_VacateResult, String> {
317	    eprintln!("vacate: removing kit assets...");
318	    eprintln!("  burc: {}", args.burc_path.display());
319	
320	    // 1. Parse BURC
321	    let burc = vofe_parse_burc(&args.burc_path)?;
322	
323	    // 2. Validate git state
324	    zvofe_check_git_clean(&burc.project_root)?;
325	
326	    // 3. Read brand file from .vvk/
327	    let brand_path = burc.project_root.join(".vvk").join("vvbf_brand.json");
328	    if !brand_path.exists() {
329	        return Err("No VVK installation found (.vvk/vvbf_brand.json missing)".to_string());
330	    }
331	    let (_brand, kit_ids) = zvofe_read_brand(&brand_path)?;
332	
333	    // 4. Remove commands and hooks
334	    let mut total_files = 0u32;
335	    let mut commands_removed = 0u32;
336	    let mut hooks_removed = 0u32;
337	
338	    let commands_dir = burc.project_root.join(".claude").join("commands");
339	    let hooks_dir = burc.project_root.join(".claude").join("hooks");
340	
341	    for kit_id in &kit_ids {
342	        // Get cipher from kit_id (e.g., "jjk" -> "jj")
343	        let cipher = &kit_id[..kit_id.len().saturating_sub(1)];
344	
345	        // Remove commands matching {cipher}c-*.md
346	        if commands_dir.exists() {
347	            commands_removed += zvofe_remove_matching_files(&commands_dir, cipher, true)?;
348	        }
349	
350	        // Remove hooks matching {cipher}h_*
351	        if hooks_dir.exists() {
352	            hooks_removed += zvofe_remove_matching_files(&hooks_dir, cipher, false)?;
353	        }
354	    }
355	
356	    // 5. Collapse CLAUDE.md: sweep legacy per-kit blocks, collapse the single
357	    //    @-include region to an UNINSTALLED breadcrumb.
358	    let claude_path = burc.project_root.join("CLAUDE.md");
359	    zvofe_collapse_claude(&claude_path)?;
360	    let section_tags = vec![VOFC_INCLUDE_REGION_TAG.to_string()];
361	
362	    // 6. Delete vvx binary from Tools/vvk/bin/
363	    // Kit directories are intentionally preserved (open-source utilities)
364	    let vvk_bin_dir = burc.tools_dir.join("vvk").join("bin");
365	    if vvk_bin_dir.exists() {
366	        let entries = fs::read_dir(&vvk_bin_dir)
367	            .map_err(|e| format!("Failed to read vvk bin dir: {}", e))?;
368	
369	        for entry in entries {
370	            let entry = entry.map_err(|e| format!("Dir entry error: {}", e))?;
371	            let path = entry.path();
372	            let file_name = path.file_name().and_then(|n| n.to_str()).unwrap_or("");
373	
374	            // Remove vvx binaries (vvx-darwin-arm64, vvx-linux-x86_64, etc.)
375	            if file_name.starts_with("vvx") {
376	                fs::remove_file(&path)
377	                    .map_err(|e| format!("Failed to remove vvx binary {}: {}", path.display(), e))?;
378	                total_files += 1;
379	                eprintln!("  removed: {}", path.display());
380	            }
381	        }
382	    }
383	
384	    // 7. Delete brand file and .vvk/
385	    fs::remove_file(&brand_path)
386	        .map_err(|e| format!("Failed to remove brand file: {}", e))?;
387	
388	    let vvk_dir = burc.project_root.join(".vvk");
389	    if vvk_dir.exists() {
390	        // Remove .vvk/ directory
391	        let _ = fs::remove_dir(&vvk_dir);
392	    }
393	
394	    // 8. Commit uninstallation
395	    zvofe_git_commit(&burc.project_root, "VVK uninstall")?;
396	
397	    eprintln!("vacate: success - {} files, {} commands, {} hooks removed", total_files, commands_removed, hooks_removed);
398	
399	    Ok(vofe_VacateResult {
400	        kits_removed: kit_ids,
401	        files_deleted: total_files,
402	        commands_removed,
403	        hooks_removed,
404	        claude_sections_collapsed: section_tags,
405	    })
406	}
