408	/// Result of forge freshen operation.
409	#[derive(Debug)]
410	pub struct vofe_FreshenResult {
411	    /// CLAUDE.md sections updated (replaced existing markers)
412	    pub updated: Vec<String>,
413	    /// CLAUDE.md sections expanded (from UNINSTALLED markers)
414	    pub expanded: Vec<String>,
415	    /// CLAUDE.md sections appended (no prior markers)
416	    pub appended: Vec<String>,
417	}
