419	/// Freshen CLAUDE.md in place (no parcel): migrate away from any legacy per-kit
420	/// inline blocks and upsert the single consolidated `@`-include region for the
421	/// kits in BURC_MANAGED_KITS. Does NOT commit — caller decides when.
422	///
423	/// # Arguments
424	/// * `burc_path` - Path to target repo's burc.env file
425	///
426	/// # Returns
427	/// FreshenResult with update summary, or error message
428	pub fn vofe_freshen_forge(burc_path: &Path) -> Result<vofe_FreshenResult, String> {
429	    let burc = vofe_parse_burc(burc_path)?;
430	    let claude_path = burc.project_root.join("CLAUDE.md");
431	
432	    let result = zvofe_freshen_claude(&claude_path, &burc, &burc.managed_kits)?;
433	
434	    for tag in &result.updated {
435	        eprintln!("  freshen: updated [{}]", tag);
436	    }
437	    for tag in &result.expanded {
438	        eprintln!("  freshen: expanded [{}] (was UNINSTALLED)", tag);
439	    }
440	    for tag in &result.appended {
441	        eprintln!("  freshen: appended [{}] (new region)", tag);
442	    }
443	
444	    Ok(vofe_FreshenResult {
445	        updated: result.updated,
446	        expanded: result.expanded,
447	        appended: result.appended,
448	    })
449	}
