574	/// Copy a kit directory and route special files.
575	/// Returns (files_copied, commands_routed, hooks_routed).
576	fn zvofe_copy_kit(
577	    source: &Path,
578	    dest: &Path,
579	    project_root: &Path,
580	    kit_id: &str,
581	) -> Result<(u32, u32, u32), String> {
582	    let mut files = 0u32;
583	    let mut commands = 0u32;
584	    let mut hooks = 0u32;
585	
586	    // Get cipher from kit_id (e.g., "jjk" -> "jj")
587	    let cipher = &kit_id[..kit_id.len().saturating_sub(1)];
588	
589	    // Walk source directory
590	    let entries = zvofe_walk_dir(source)?;
591	
592	    for entry in entries {
593	        let rel_path = entry
594	            .strip_prefix(source)
595	            .map_err(|e| format!("Path strip failed: {}", e))?;
596	
597	        let file_name = rel_path
598	            .file_name()
599	            .and_then(|n| n.to_str())
600	            .unwrap_or("");
601	
602	        // Determine destination based on file type
603	        let dest_path = if zvofe_is_command_file(file_name, cipher) {
604	            // Route commands to .claude/commands/
605	            let commands_dir = project_root.join(".claude").join("commands");
606	            fs::create_dir_all(&commands_dir)
607	                .map_err(|e| format!("Failed to create commands dir: {}", e))?;
608	            commands += 1;
609	            commands_dir.join(file_name)
610	        } else if zvofe_is_hook_file(file_name, cipher) {
611	            // Route hooks to .claude/hooks/
612	            let hooks_dir = project_root.join(".claude").join("hooks");
613	            fs::create_dir_all(&hooks_dir)
614	                .map_err(|e| format!("Failed to create hooks dir: {}", e))?;
615	            hooks += 1;
616	            hooks_dir.join(file_name)
617	        } else {
618	            // Default: preserve relative path in kit directory
619	            dest.join(rel_path)
620	        };
621	
622	        // Create parent directories
623	        if let Some(parent) = dest_path.parent() {
624	            fs::create_dir_all(parent)
625	                .map_err(|e| format!("Failed to create dir {}: {}", parent.display(), e))?;
626	        }
627	
628	        // Copy file
629	        fs::copy(&entry, &dest_path)
630	            .map_err(|e| format!("Failed to copy {} to {}: {}", entry.display(), dest_path.display(), e))?;
631	
632	        files += 1;
633	    }
634	
635	    Ok((files, commands, hooks))
636	}
