638	/// Walk directory recursively, returning all file paths.
639	fn zvofe_walk_dir(dir: &Path) -> Result<Vec<PathBuf>, String> {
640	    let mut files = Vec::new();
641	
642	    if !dir.is_dir() {
643	        return Ok(files);
644	    }
645	
646	    let entries = fs::read_dir(dir)
647	        .map_err(|e| format!("Failed to read dir {}: {}", dir.display(), e))?;
648	
649	    for entry in entries {
650	        let entry = entry.map_err(|e| format!("Dir entry error: {}", e))?;
651	        let path = entry.path();
652	
653	        if path.is_dir() {
654	            files.extend(zvofe_walk_dir(&path)?);
655	        } else {
656	            files.push(path);
657	        }
658	    }
659	
660	    Ok(files)
661	}
