670	fn zvofe_is_hook_file(file_name: &str, cipher: &str) -> bool {
671	    let prefix = format!("{}{}", cipher, VOFC_HOOK_SIGNET_SUFFIX);
672	    file_name.starts_with(&prefix) && file_name.ends_with(".md")
673	}
