677	fn zvofe_route_claude_assets(
678	    parcel_dir: &Path,
679	    project_root: &Path,
680	) -> Result<(u32, u32), String> {
681	    let mut commands_count = 0u32;
682	    let mut hooks_count = 0u32;
683	
684	    // Route commands from parcel claude/commands/ to target .claude/commands/
685	    let commands_source = parcel_dir.join("claude").join("commands");
