690	
691	        commands_count = zvofe_copy_all_files(&commands_source, &commands_dest)?;
692	    }
693	
694	    // Route hooks from parcel claude/hooks/ to target .claude/hooks/
695	    let hooks_source = parcel_dir.join("claude").join("hooks");
696	    if hooks_source.exists() {
697	        let hooks_dest = project_root.join(".claude").join("hooks");
698	        fs::create_dir_all(&hooks_dest)
699	            .map_err(|e| format!("Failed to create .claude/hooks dir: {}", e))?;
700	
701	        hooks_count = zvofe_copy_all_files(&hooks_source, &hooks_dest)?;
702	    }
703	
704	    Ok((commands_count, hooks_count))
