707	/// Copy all files from source directory to dest directory.
708	/// Returns count of files copied.
709	fn zvofe_copy_all_files(source_dir: &Path, dest_dir: &Path) -> Result<u32, String> {
710	    let mut count = 0u32;
711	
712	    let entries = fs::read_dir(source_dir)
713	        .map_err(|e| format!("Failed to read directory {}: {}", source_dir.display(), e))?;
714	
715	    for entry in entries {
716	        let entry = entry.map_err(|e| format!("Dir entry error: {}", e))?;
717	        let path = entry.path();
718	
719	        if !path.is_file() {
720	            continue;
721	        }
722	
723	        let file_name = path
724	            .file_name()
725	            .ok_or_else(|| format!("No file name for {}", path.display()))?;
726	
727	        let dest_path = dest_dir.join(file_name);
728	        fs::copy(&path, &dest_path)
729	            .map_err(|e| format!("Failed to copy {} to {}: {}", path.display(), dest_path.display(), e))?;
730	        count += 1;
731	    }
732	
733	    Ok(count)
