736	/// Freshen CLAUDE.md: migrate away from any legacy per-kit inline blocks and
737	/// upsert the single consolidated `@`-include region for the installed kits.
738	///
739	/// Returns the underlying freshen result (updated/expanded/appended) so the
740	/// standalone forge-freshen path can report what changed.
741	fn zvofe_freshen_claude(
742	    claude_path: &Path,
743	    burc: &vofe_BurcEnv,
744	    kit_ids: &[String],
745	) -> Result<voff_FreshenResult, String> {
746	    let content = if claude_path.exists() {
747	        fs::read_to_string(claude_path)
748	            .map_err(|e| format!("Failed to read CLAUDE.md: {}", e))?
749	    } else {
750	        "# Claude Code Project Memory\n".to_string()
751	    };
752	
753	    // Migration: excise legacy per-kit MANAGED blocks (old inline model).
754	    let legacy_tags = zvofe_legacy_tags();
755	    let legacy_refs: Vec<&str> = legacy_tags.iter().map(|s| s.as_str()).collect();
756	    let swept = voff_remove_regions(&content, &legacy_refs);
757	
758	    // Upsert the single @-include region.
759	    let section = voff_ManagedSection {
760	        tag: VOFC_INCLUDE_REGION_TAG.to_string(),
761	        content: zvofe_build_include_body(burc, kit_ids)?,
762	    };
763	    let result = voff_freshen(&swept, std::slice::from_ref(&section));
764	
765	    fs::write(claude_path, &result.content)
766	        .map_err(|e| format!("Failed to write CLAUDE.md: {}", e))?;
767	
768	    Ok(result)
769	}
