771	/// Legacy per-kit managed-section tags (uppercased kit id) from the old inline
772	/// model. Swept on every freshen so a once-installed consumer migrates cleanly.
773	fn zvofe_legacy_tags() -> Vec<String> {
774	    DISTRIBUTABLE_KITS
775	        .iter()
776	        .map(|k| k.cipher.kit_id().to_uppercase())
777	        .collect()
778	}
