812	/// Collapse CLAUDE.md for uninstall: excise any legacy per-kit blocks and
813	/// collapse the single `@`-include region to an UNINSTALLED breadcrumb (so a
814	/// future reinstall re-expands it in place).
815	fn zvofe_collapse_claude(claude_path: &Path) -> Result<(), String> {
816	    if !claude_path.exists() {
817	        return Ok(()); // Nothing to collapse
818	    }
819	
820	    let content = fs::read_to_string(claude_path)
821	        .map_err(|e| format!("Failed to read CLAUDE.md: {}", e))?;
822	
823	    let legacy_tags = zvofe_legacy_tags();
824	    let legacy_refs: Vec<&str> = legacy_tags.iter().map(|s| s.as_str()).collect();
825	    let swept = voff_remove_regions(&content, &legacy_refs);
826	    let collapsed = voff_collapse(&swept, &[VOFC_INCLUDE_REGION_TAG]);
827	
828	    fs::write(claude_path, &collapsed)
829	        .map_err(|e| format!("Failed to write CLAUDE.md: {}", e))?;
830	
831	    Ok(())
832	}
