140	/// Brand a staging directory with brand and metadata.
141	///
142	/// # Arguments
143	/// * `staging_dir` - Staging directory with collected assets
144	/// * `registry_path` - Path to vovr_registry.json
145	/// * `commit_sha` - Current git commit SHA
146	/// * `managed_kits` - List of kit IDs included (from BURC_MANAGED_KITS)
147	///
148	/// # Returns
149	/// BrandResult with brand info, or error message
150	pub fn vofr_brand(
151	    staging_dir: &Path,
152	    registry_path: &Path,
153	    commit_sha: &str,
154	    managed_kits: &[String],
155	) -> Result<vofr_BrandResult, String> {
156	    // Compute super-SHA of staging content
157	    let super_sha = zvofr_compute_super_sha(staging_dir)?;
158	
159	    // Load or create registry
160	    let mut registry = zvofr_load_registry(registry_path)?;
161	
162	    // Check if SHA already exists
163	    let (brand, is_new) = if let Some(existing) = zvofr_find_by_sha(&registry, &super_sha) {
164	        (existing, false)
165	    } else {
166	        let new_brand = zvofr_allocate_brand(&registry);
167	        (new_brand, true)
168	    };
169	
170	    // Generate timestamp
171	    let date = zvofr_generate_date();
172	
173	    // If new, update registry
174	    if is_new {
175	        registry.insert(brand, vofr_RegistryEntry {
176	            date: date.clone(),
177	            sha: super_sha.clone(),
178	        });
179	        zvofr_save_registry(registry_path, &registry)?;
180	    }
181	
182	    // Write brand file with managed_kits as the kit list
183	    let brand_path = staging_dir.join("vvbf_brand.json");
184	    zvofr_write_brand_file(&brand_path, brand, &date, &super_sha, commit_sha, managed_kits)?;
185	
186	    Ok(vofr_BrandResult {
187	        brand,
188	        is_new,
189	        super_sha,
190	    })
191	}
